import { cookies } from "next/headers";
import { redirect } from "next/navigation";
import { ReactNode } from "react";

export default async function AdminLayout({ children }: { children: ReactNode }) {
  const cookieStore = cookies();
  const token = cookieStore.get("bicta_token")?.value;

  if (!token) {
    redirect("/login?next=/admin");
  }

  let isAdmin = false;
  try {
    const res = await fetch(
      `${process.env.BICTA_API_URL || "https://bicta-site-production.up.railway.app"}/trpc/auth.me`,
      { headers: { Cookie: `bicta_token=${token}` }, cache: "no-store" }
    );
    if (res.ok) {
      const data = await res.json();
      const role = data?.result?.data?.role;
      isAdmin = role === "admin";
    }
  } catch {
    // backend unreachable — check token payload as fallback
    try {
      const payload = JSON.parse(atob(token.split(".")[1]));
      isAdmin = payload?.role === "admin";
    } catch {
      isAdmin = false;
    }
  }

  if (!isAdmin) {
    redirect("/login?next=/admin");
  }

  return <>{children}</>;
}

import { NextRequest, NextResponse } from "next/server";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { email, password } = body;

    if (!email || !password) {
      return NextResponse.json({ error: "Email and password required" }, { status: 400 });
    }

    const apiUrl = process.env.BICTA_API_URL || "https://bicta-site-production.up.railway.app";
    const upstream = await fetch(`${apiUrl}/trpc/auth.login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ json: { email, password } }),
    });

    if (!upstream.ok) {
      const err = await upstream.json().catch(() => ({}));
      return NextResponse.json(
        { error: err?.error?.message || "Invalid credentials" },
        { status: 401 }
      );
    }

    const data = await upstream.json();
    const token = data?.result?.data?.token;
    const user  = data?.result?.data?.user;

    if (!token) {
      return NextResponse.json({ error: "Login failed — no token returned" }, { status: 401 });
    }

    const response = NextResponse.json({ ok: true, user });
    response.cookies.set("bicta_token", token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: "lax",
      maxAge: 60 * 60 * 24 * 7, // 7 days
      path: "/",
    });
    return response;
  } catch (e) {
    console.error("Login error:", e);
    return NextResponse.json({ error: "Server error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";

export async function POST() {
  const response = NextResponse.json({ ok: true });
  response.cookies.set("bicta_token", "", {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "lax",
    maxAge: 0,
    path: "/",
  });
  return response;
}

import { NextRequest, NextResponse } from "next/server";

export async function GET(req: NextRequest) {
  const token = req.cookies.get("bicta_token")?.value;
  if (!token) return NextResponse.json({ user: null }, { status: 401 });

  try {
    const apiUrl = process.env.BICTA_API_URL || "https://bicta-site-production.up.railway.app";
    const res = await fetch(`${apiUrl}/trpc/auth.me`, {
      headers: { Cookie: `bicta_token=${token}` },
      cache: "no-store",
    });
    if (!res.ok) return NextResponse.json({ user: null }, { status: 401 });
    const data = await res.json();
    return NextResponse.json({ user: data?.result?.data });
  } catch {
    // fallback: decode JWT payload
    try {
      const payload = JSON.parse(atob(token.split(".")[1]));
      return NextResponse.json({ user: payload });
    } catch {
      return NextResponse.json({ user: null }, { status: 401 });
    }
  }
}

"use client";
import { useState, useEffect, useCallback } from "react";

export interface AuthUser {
  id: number;
  email: string;
  name: string;
  role: "admin" | "participant" | "judge" | "partner";
}

export function useAuth() {
  const [user, setUser]       = useState<AuthUser | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/auth/me", { credentials: "include" })
      .then(r => r.ok ? r.json() : { user: null })
      .then(d => setUser(d.user ?? null))
      .catch(() => setUser(null))
      .finally(() => setLoading(false));
  }, []);

  const logout = useCallback(async () => {
    await fetch("/api/auth/logout", { method: "POST", credentials: "include" });
    setUser(null);
    window.location.href = "/login";
  }, []);

  return { user, loading, logout, isAdmin: user?.role === "admin" };
}

"use client";
import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/hooks/useAuth";
import ExamInterface from "@/components/competition/ExamInterface";

export default function ExamPage() {
  const { user, loading } = useAuth();
  const router = useRouter();

  useEffect(() => {
    if (!loading && !user) {
      router.replace("/login?next=/competition/exam");
    }
  }, [user, loading, router]);

  if (loading) {
    return (
      <div className="min-h-screen bg-bicta-void flex items-center justify-center">
        <div className="text-bicta-subtle text-sm">Verifying identity…</div>
      </div>
    );
  }

  if (!user) return null;

  return <ExamInterface />;
}
